// 실적번호(숫자 1~5) 기준으로 그룹핑
const items = $input.all();
const groups = {};

for (const item of items) {
  const meta = item.json.메타데이터 || {};
  const 실적번호 = meta.실적번호;

  if (실적번호 === undefined || 실적번호 === null || 실적번호 === '알 수 없음') {
    console.log('경고: 실적번호 불명 아이템:', JSON.stringify(meta));
    continue;
  }

  const key = String(실적번호);

  if (!groups[key]) {
    groups[key] = {
      실적번호:   실적번호,
      실적인덱스: meta.실적인덱스 ?? -1,
      평가항목:   meta.평가항목  || '',
      제출시간:   meta.제출시간  || '',
      파일수:     0,
      파일목록:   [],
      문서목록:   []
    };
  }

  groups[key].파일목록.push(meta.원본파일명);
  groups[key].문서목록.push(item.json);
  groups[key].파일수 = groups[key].문서목록.length;
}

const sorted = Object.values(groups)
  .sort((a, b) => a.실적인덱스 - b.실적인덱스)
  .map(g => ({ json: g }));

console.log('그룹핑 결과:');
sorted.forEach(s =>
  console.log(`  실적 ${s.json.실적번호}: ${s.json.파일수}개 - [${s.json.파일목록.join(', ')}]`)
);

return sorted;

// Read PDF 실행 후 json = { text:'...' } 만 남음
// → $('Expand All Files').all()[idx] 로 _meta 복원
// → 문서제목은 파일명 그대로 사용

const items         = $input.all();
const expandedItems = $('Expand All Files').all();

console.log(`Structure PDF Data: items=${items.length}, expandedItems=${expandedItems.length}`);

return items.map((item, idx) => {
  const text = item.json.text || '';

  const expandedItem = expandedItems[idx];
  const meta = (expandedItem && expandedItem.json && expandedItem.json._meta)
    ? expandedItem.json._meta
    : {};

  const 실적번호     = meta.실적번호     !== undefined ? meta.실적번호     : '알 수 없음';
  const 실적인덱스   = meta.실적인덱스   !== undefined ? meta.실적인덱스   : -1;
  const 파일명       = meta.파일명       || '알 수 없음';
  const 파일순번     = meta.파일순번     || 1;
  const 실적내파일수 = meta.실적내파일수 || 1;
  const 제출시간     = meta.제출시간     || '';

  console.log(`[${idx}] 실적번호: ${실적번호}, 파일명: ${파일명}`);

  function removeDuplicateWords(t) {
    const words = t.split(/\s+/);
    const result = []; let prev = '';
    for (const w of words) { if (w !== prev) { result.push(w); prev = w; } }
    return result.join(' ');
  }

  function removeDuplicateSentences(t) {
    t = removeDuplicateWords(t);
    const words = t.split(/\s+/);
    const max = Math.floor(words.length / 2);
    for (let len = max; len >= 3; len--) {
      const a = words.slice(0, len).join(' ');
      const b = words.slice(len, len * 2).join(' ');
      if (a === b) return a + ' ' + words.slice(len).join(' ');
    }
    return t;
  }

  function extractMainSections(text) {
    const sections = {};
    const matches  = [...text.matchAll(/□\s*([^\n]+)/g)];
    for (let i = 0; i < matches.length; i++) {
      const title = matches[i][1].trim();
      const start = matches[i].index + matches[i][0].length;
      const end   = i < matches.length - 1 ? matches[i+1].index : text.length;
      sections[title] = text.slice(start, end).trim();
    }
    return sections;
  }

  function parseSubSections(content) {
    const matches = [...content.matchAll(/❍\s*\(\s*([^)]+)\s*\)/g)];
    if (matches.length === 0) return content.replace(/^\s*❍\s*/gm, '').trim();
    const result = {};
    for (let i = 0; i < matches.length; i++) {
      const sub   = matches[i][1].trim();
      const start = matches[i].index + matches[i][0].length;
      const end   = i < matches.length - 1 ? matches[i+1].index : content.length;
      result[sub] = content.slice(start, end)
        .replace(/^\s*-\s*/gm, '').replace(/^\s*❍\s*/gm, '').trim();
    }
    return result;
  }

  const mainSections = extractMainSections(text);

  const structuredData = {
    메타데이터: {
      문서제목:     파일명.replace(/\.pdf$/i, ''),
      원본파일명:   파일명,
      실적번호:     실적번호,
      실적인덱스:   실적인덱스,
      파일순번:     파일순번,
      실적내파일수: 실적내파일수,
      평가항목:     '선택 안됨',
      제출시간:     제출시간
    }
  };

  for (const [sTitle, sContent] of Object.entries(mainSections)) {
    structuredData[sTitle] = parseSubSections(sContent);
  }
  structuredData['원본텍스트'] = text;

  console.log('구조화 완료:', JSON.stringify(structuredData.메타데이터));
  return { json: structuredData };
});

// 실적 1~5의 모든 PDF를 개별 아이템으로 펼치기
// _meta를 json에 직접 포함 → Structure PDF Data에서 $('Expand All Files').all()[idx]로 참조

const formItem   = $input.first();
const formJson   = formItem.json;
const formBinary = formItem.binary || {};
const allBinaryKeys = Object.keys(formBinary);

console.log('=== Expand All Files 시작 ===');
console.log('바이너리 키 목록:', allBinaryKeys);

const 실적필드목록 = ['실적 1', '실적 2', '실적 3', '실적 4', '실적 5'];
const outputItems = [];

for (let i = 0; i < 실적필드목록.length; i++) {
  const fieldName = 실적필드목록[i];
  const 실적번호  = i + 1;
  const files = formJson[fieldName];

  if (!files || !Array.isArray(files) || files.length === 0) {
    console.log(`실적 ${실적번호}: 파일 없음, 건너뜀`);
    continue;
  }

  for (let j = 0; j < files.length; j++) {
    const file     = files[j];
    const fileName = file.filename || '알 수 없음';
    const mimeType = file.mimetype || 'application/pdf';

    let matchedKey = allBinaryKeys.find(key => {
      const b = formBinary[key];
      return b.fileName === fileName || b.filename === fileName;
    });

    if (!matchedKey) {
      let globalIdx = 0;
      for (let pi = 0; pi < i; pi++) {
        const pf = formJson[실적필드목록[pi]];
        if (pf && Array.isArray(pf)) globalIdx += pf.length;
      }
      globalIdx += j;
      matchedKey = allBinaryKeys[globalIdx];
      console.log(`실적${실적번호} 파일명 매칭 실패 → 인덱스(${globalIdx}) 대체: ${matchedKey}`);
    }

    if (!matchedKey || !formBinary[matchedKey]) {
      console.log(`실적${실적번호} - ${fileName}: 바이너리 없음, 건너뜀`);
      continue;
    }

    const globalItemIndex = outputItems.length;

    outputItems.push({
      json: {
        _meta: {
          _itemIndex:    globalItemIndex,
          실적번호:       실적번호,
          실적인덱스:     i,
          파일명:         fileName,
          파일순번:       j + 1,
          실적내파일수:   files.length,
          제출시간:       formJson.submittedAt || ''
        }
      },
      binary: {
        data: {
          ...formBinary[matchedKey],
          mimeType:      formBinary[matchedKey].mimeType || mimeType,
          fileExtension: formBinary[matchedKey].fileExtension || 'pdf'
        }
      }
    });

    console.log(`실적${실적번호} - 파일 ${j+1}: ${fileName} → 아이템 인덱스 ${globalItemIndex}`);
  }
}

console.log(`=== 총 ${outputItems.length}개 아이템 생성 완료 ===`);
return outputItems;

