const buffer = Buffer.from(html, 'utf-8');
const fileName = `공공데이터_활용지원_정성보고서_${new Date().toISOString().split('T')[0]}.html`;

return [{
  json: { 생성파일명: fileName, 실적수: 실적목록.length },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'text/html',
      fileName,
      fileExtension: 'html'
    }
  }
}];

// Label Report Items - 실적별로 문서목록 전체에 라벨 부여
const items = $input.all();

function findSectionsByKeywords(dataObj, keywords) {
  const found = [];
  if (!dataObj || typeof dataObj !== 'object') return found;
  for (const [sectionTitle, sectionContent] of Object.entries(dataObj)) {
    if (sectionTitle === '메타데이터' || sectionTitle === '원본텍스트') continue;
    const titleLower = String(sectionTitle).toLowerCase();
    for (const keyword of keywords) {
      if (titleLower.includes(String(keyword).toLowerCase())) {
        found.push({ 제목: sectionTitle, 내용: sectionContent });
        break;
      }
    }
  }
  return found;
}

function labelDocument(data) {
  const docTitle = data.메타데이터?.문서제목 || data.메타데이터?.원본파일명 || '';

  const 추진실적명데이터 = {
    항목명: '추진실적명',
    출처: '메타데이터.문서제목(파일명)',
    찾은섹션: docTitle ? [{ 제목: '문서제목', 내용: docTitle }] : []
  };

